"""
This is the main module to launch the program
"""

from board import Board
from player import Player, HumanPlayer

def run():
    players = [HumanPlayer(color='black'), HumanPlayer(color='white')]
    board = Board()

    current_player = players[0]
    while True:
        print(board)
        move = current_player.get_move()
        if not board.apply_move(move):
            print("Invalid move. Try again.")
            continue

        if board.check_win():
            print(f"Player {current_player.color} wins!")
            break

        current_player = players[1 - players.index(current_player)]

if __name__ == "__main__":
    run()
```

